    page.getByRole("heading", {
      name: "SAP Integration Suite Contract Discount Optional",
    }),
  ).toBeVisible();
  await page.locator("#is-discount-toggle").click();
  await expect(page.locator("#is-discount-toggle")).toHaveAttribute(
    "aria-checked",
    "true",
  );

